function calculateScore(userQuery, itemKeywords) {
  let score = 0;
  const userWords = userQuery.split(/\s+/).filter(w => w.length > 2);
  const userWordSet = new Set(userWords);

  let targetWordSet = new Set();
  itemKeywords.forEach(phrase => {
    const words = phrase.split(/\s+/);
    words.forEach(w => targetWordSet.add(w));
  });

  const PHRASE_MATCH_SCORE = 50;
  const WORD_MATCH_SCORE = 15;

  itemKeywords.forEach(phrase => {
    if (userQuery.includes(phrase)) {
      score += PHRASE_MATCH_SCORE;
    }
  });

  let matchedWordsCount = 0;
  userWordSet.forEach(uWord => {
    if (targetWordSet.has(uWord)) {
      matchedWordsCount++;
    } 
    else {
      for (let tWord of targetWordSet) {
        if (tWord.includes(uWord) || uWord.includes(tWord)) {
          if (Math.abs(tWord.length - uWord.length) <= 2) {
             matchedWordsCount++;
             break;
          }
        }
      }
    }
  });

  score += (matchedWordsCount * WORD_MATCH_SCORE);
  return score;
}

let finalQuery = userInput;
let isMatched = false;
let matchType = "NONE";
let bestScore = 0;
let bestMatch = null;

const exactMatch = faqMapping.find(item => 
  item.target.toLowerCase() === normalizedInput
);

if (exactMatch) {
  finalQuery = exactMatch.target;
  isMatched = true;
  matchType = "EXACT";
  bestScore = 1000;
} else {
  faqMapping.forEach(item => {
    const score = calculateScore(normalizedInput, item.keywords);
    if (score > bestScore) {
      bestScore = score;
      bestMatch = item;
    }
  });

  if (bestScore >= 25 && bestMatch) {
    finalQuery = bestMatch.target;
    isMatched = true;
    matchType = "FUZZY";
  }
}

console.log('=== QUERY MATCH RESULT ===');
